query:
-- ช่วงวันที่ของ rows ที่ payment_time IS NULL
SELECT MIN(paid_at) as oldest, MAX(paid_at) as newest, COUNT(*) as cnt 
FROM payment_transactions WHERE section='ff365' AND payment_time IS NULL;

-- ช่วงวันที่ของ rows ที่ payment_time มีค่า
SELECT MIN(paid_at) as oldest, MAX(paid_at) as newest, COUNT(*) as cnt 
FROM payment_transactions WHERE section='ff365' AND payment_time IS NOT NULL;

-- กระจายตัวของ payment_time IS NULL ตามปี
SELECT LEFT(paid_at, 4) as yr, COUNT(*) as cnt 
FROM payment_transactions WHERE section='ff365' AND payment_time IS NULL 
GROUP BY yr ORDER BY yr;

